import React from 'react'
const Home = React.lazy(
    () => import('./../pages/home/home'),
)
const About = React.lazy(
    () => import('./../pages/about/about'),
)
const Blog = React.lazy(
    () => import('./../pages/blog/blog'),
)
const Work = React.lazy(
    () => import('./../pages/work/work'),
)
const Contact = React.lazy(
    () => import('./../pages/contact/contact'),
)

const Preloader = React.lazy(
    () => import('./../components/preloader'),
)

var mainRoutes = [
    { path: '/howard-ho', name: 'Homepage', component: <Home /> },
    { path: '/howard-ho/about', name: 'About', component: <About /> },
    { path: '/howard-ho/blog', name: 'Blog', component: <Blog /> },
    { path: '/howard-ho/work', name: 'Work', component: <Work /> },
    { path: '/howard-ho/contact', name: 'Contact', component: <Contact /> },
    { path: '/howard-ho/preloader', name: 'Preloader', component: <Preloader /> },
]

export default mainRoutes
